describe('Delta transform', () => {
  it('should not apply embed handler when thisOp retain is numeric and otherOp retain is an object embed', () => {
    Delta.registerEmbed('video', {
      compose: (a: any, b: any, keepNull: boolean) => b,
      invert: (a: any, b: any) => b,
      transform: (_a: any, _b: any, _priority: boolean) => ({ mutated: true }),
